import{_ as o,o as a,c as r,ae as n}from"./chunks/framework.C8MNLDzb.js";const d=JSON.parse('{"title":"战国策典故","description":"","frontmatter":{},"headers":[],"relativePath":"docs/sucai/diangu/jing/战国策.md","filePath":"docs/sucai/diangu/jing/战国策.md"}'),s={name:"docs/sucai/diangu/jing/战国策.md"};function e(u,t,g,i,q,h){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="战国策典故" tabindex="-1">战国策典故 <a class="header-anchor" href="#战国策典故" aria-label="Permalink to &quot;战国策典故&quot;">​</a></h1><h2 id="合纵连横" tabindex="-1">合纵连横 <a class="header-anchor" href="#合纵连横" aria-label="Permalink to &quot;合纵连横&quot;">​</a></h2><p><strong>典故：</strong> 战国时期，苏秦游说六国联合抗秦，称之为&quot;合纵&quot;；张仪游说六国服从秦国，称之为&quot;连横&quot;。苏秦佩六国相印，一时显赫；张仪为秦相，以连横之术瓦解六国联盟。 <strong>出处：</strong> 《战国策·秦策》《战国策·齐策》 <strong>释义：</strong> 合纵指联合众多弱国对抗强国，连横指弱国依附强国。后多用于形容纵横捭阖的外交策略。</p><h2 id="负荆请罪" tabindex="-1">负荆请罪 <a class="header-anchor" href="#负荆请罪" aria-label="Permalink to &quot;负荆请罪&quot;">​</a></h2><p><strong>典故：</strong> 赵国蔺相如因完璧归赵被封为上卿，位在廉颇之上。廉颇不服，扬言要当面羞辱蔺相如。蔺相如为顾全赵国大局，处处忍让躲避。廉颇得知后肉袒负荆，到蔺相如门前请罪说：&quot;鄙贱之人，不知将军宽之至此也。&quot; <strong>出处：</strong> 《战国策·赵策》 <strong>释义：</strong> 形容主动向对方承认错误，请求对方惩罚，表示真诚悔过。</p><h2 id="毛遂自荐" tabindex="-1">毛遂自荐 <a class="header-anchor" href="#毛遂自荐" aria-label="Permalink to &quot;毛遂自荐&quot;">​</a></h2><p><strong>典故：</strong> 秦国围攻赵国都城邯郸，平原君要去楚国求救，门客毛遂请求同往。平原君说：&quot;有才能的人就像锥子在口袋里，锥尖马上就会露出来。你在我这里三年，没有表现。&quot;毛遂说：&quot;我今天就请求被放进口袋里。如果早被放进去，早就脱颖而出。&quot;到楚国后，毛遂果然说服楚王出兵救赵。 <strong>出处：</strong> 《战国策·赵策》 <strong>释义：</strong> 比喻主动推荐自己，承担重要任务。</p><h2 id="狡兔三窟" tabindex="-1">狡兔三窟 <a class="header-anchor" href="#狡兔三窟" aria-label="Permalink to &quot;狡兔三窟&quot;">​</a></h2><p><strong>典故：</strong> 孟尝君的门客冯驩为他出谋划策，说：&quot;狡兔有三窟，仅得免其死耳。今君有一窟，未得高枕而卧也。&quot;于是冯驩为孟尝君凿了三个安身之处，让孟尝君得以安稳无忧。 <strong>出处：</strong> 《战国策·齐策》 <strong>释义：</strong> 狡猾的兔子有三个窝，比喻有多处藏身之地，或多种避祸准备。</p><h2 id="惊弓之鸟" tabindex="-1">惊弓之鸟 <a class="header-anchor" href="#惊弓之鸟" aria-label="Permalink to &quot;惊弓之鸟&quot;">​</a></h2><p><strong>典故：</strong> 更羸与魏王在高台之下，抬头看见飞鸟。更羸说：&quot;我为虚发而下鸟。&quot;他引弓虚发，果然有鸟坠落。魏王问其原因，更羸说：&quot;此鸟受箭伤未愈，闻弦音烈，惊慌高飞，旧疮迸裂，故坠落。&quot; <strong>出处：</strong> 《战国策·楚策》 <strong>释义：</strong> 比喻受过惊吓的人遇到类似情况更加惊恐。</p><h2 id="狐假虎威" tabindex="-1">狐假虎威 <a class="header-anchor" href="#狐假虎威" aria-label="Permalink to &quot;狐假虎威&quot;">​</a></h2><p><strong>典故：</strong> 老虎抓住狐狸要吃它，狐狸说：&quot;你不敢吃我，天帝派我做百兽之王。不信你跟在我后面走，看百兽见了我有没有不逃跑的。&quot;老虎跟着狐狸走，百兽果然纷纷奔逃。老虎以为真的是怕狐狸，其实怕的是老虎。 <strong>出处：</strong> 《战国策·楚策》 <strong>释义：</strong> 比喻仗着别人的势力欺压人。</p><h2 id="南辕北辙" tabindex="-1">南辕北辙 <a class="header-anchor" href="#南辕北辙" aria-label="Permalink to &quot;南辕北辙&quot;">​</a></h2><p><strong>典故：</strong> 有人对魏王说：&quot;我想到楚国去。&quot;魏王问他：&quot;去楚国往南走，你为什么却往北走？&quot;他说：&quot;我的马好。&quot;魏王说：&quot;马虽好，但这不是去楚国的路。&quot;他说：&quot;我路费多。&quot;魏王说：&quot;路费虽多，但这不是去楚国的方向。&quot;他说：&quot;我车夫技术高。&quot; <strong>出处：</strong> 《战国策·魏策》 <strong>释义：</strong> 心想往南而车子却向北走，比喻行动与目的相反。</p><h2 id="鹬蚌相争" tabindex="-1">鹬蚌相争 <a class="header-anchor" href="#鹬蚌相争" aria-label="Permalink to &quot;鹬蚌相争&quot;">​</a></h2><p><strong>典故：</strong> 蚌张开壳晒太阳，鹬啄住蚌肉，两者僵持不下。渔翁路过，轻轻将两者一起捉住。 <strong>出处：</strong> 《战国策·燕策》 <strong>释义：</strong> 比喻双方争执不下，结果两败俱伤，让第三方得利。</p><h2 id="画蛇添足" tabindex="-1">画蛇添足 <a class="header-anchor" href="#画蛇添足" aria-label="Permalink to &quot;画蛇添足&quot;">​</a></h2><p><strong>典故：</strong> 楚国有一家人祭祀后赏酒，门客们商量：&quot;几人以画蛇最快者饮。&quot;一人先画完，却说&quot;吾能为之足&quot;，于是给蛇添上脚。另一人画完说：&quot;蛇固无足，子安能为之足？&quot;夺过酒来一饮而尽。那个画蛇添足的人，最终没有喝到酒。 <strong>出处：</strong> 《战国策·齐策》 <strong>释义：</strong> 比喻做了多余的事，反而把事情弄糟。</p><h2 id="千金市骨" tabindex="-1">千金市骨 <a class="header-anchor" href="#千金市骨" aria-label="Permalink to &quot;千金市骨&quot;">​</a></h2><p><strong>典故：</strong> 古代有位国君想用千金买千里马，三年不能得。后来派侍臣用五百金买回一匹已死的千里马骨头。国君大怒，侍臣说：&quot;死马且市之三千金，况生马乎？&quot;果然，不到一年，得到三匹千里马。 <strong>出处：</strong> 《战国策·燕策》 <strong>释义：</strong> 比喻招揽人才的心切，或用来比喻重视人才。</p><h2 id="冯驩收债" tabindex="-1">冯驩收债 <a class="header-anchor" href="#冯驩收债" aria-label="Permalink to &quot;冯驩收债&quot;">​</a></h2><p><strong>典故：</strong> 孟尝君派冯驩去封地薛城收债，冯驩到了薛城，把债券全部烧掉，回去后对孟尝君说：&quot;我为你买来了&#39;义&#39;。&quot;后来孟尝君失宠，被遣回薛城，距离薛城百里时，百姓扶老携幼前来迎接。孟尝君这才明白冯驩的远见。 <strong>出处：</strong> 《战国策·齐策》 <strong>释义：</strong> 比喻重视民心，或讽刺只看眼前利益。</p><h2 id="远交近攻" tabindex="-1">远交近攻 <a class="header-anchor" href="#远交近攻" aria-label="Permalink to &quot;远交近攻&quot;">​</a></h2><p><strong>典故：</strong> 范雎向秦昭王献策：&quot;王不如远交而近攻，得寸则王之寸也，得尺亦王之尺也。今舍此而远攻，不亦谬乎？&quot; <strong>出处：</strong> 《战国策·秦策》 <strong>释义：</strong> 结交远方的国家，攻打邻近的国家，是秦国统一六国的外交和军事策略。</p>',25)])])}const c=o(s,[["render",e]]);export{d as __pageData,c as default};
